Advanced directory query (users with filter + count):
```python
def list_users_filtered(session, filter_expr):
    url = 'https://graph.microsoft.com/v1.0/users'
    params = {'$filter': filter_expr, '$count': 'true', '$select': 'id,displayName,mail,accountEnabled'}
    headers = {'ConsistencyLevel': 'eventual'}  # REQUIRED for directory advanced queries
    resp = session.get(url, params=params, headers=headers, timeout=(10, 30))
    resp.raise_for_status()
    return resp.json()
```

Batch request:
```python
def graph_batch(session, requests_list):
    batch = {'requests': [{'id': str(i), 'method': r['method'], 'url': r['url']} for i, r in enumerate(requests_list)]}
    resp = session.post('https://graph.microsoft.com/v1.0/$batch', json=batch, timeout=(10, 60))
    resp.raise_for_status()
    return {r['id']: r for r in resp.json()['responses']}
```

Robust error handling:
```python
def graph_get(session, url, **kwargs):
    resp = session.get(url, timeout=(10, 30), **kwargs)
    if resp.status_code == 429:
        wait = int(resp.headers.get('Retry-After', 60))
        time.sleep(wait)
        resp = session.get(url, timeout=(10, 30), **kwargs)
    if resp.status_code >= 400:
        error = resp.json().get('error', {})
        raise RuntimeError(f"Graph {resp.status_code}: {error.get('code')} — {error.get('message')}")
    return resp.json()
```
